# Risk-gated checkpoint: only ask for human approval on high-risk steps.
# Low-risk steps (reads, searches) auto-approve; write/delete steps pause.

RISKY_TOOLS = {'write_file', 'delete_file', 'send_email', 'post_api', 'run_sql'}

def is_risky(tool_name: str, tool_input: dict) -> bool:
    if tool_name in RISKY_TOOLS:
        return True
    # Also flag if input contains irreversible keywords
    input_str = str(tool_input).lower()
    return any(kw in input_str for kw in ('delete', 'drop', 'truncate', 'overwrite'))

def run_with_human_gates(
    client,
    goal: str,
    tools: list[dict],
    tool_fns: dict,
    ask_fn: Callable[[str], tuple[HumanDecision, str]],
    max_steps: int = 20,
) -> str:
    messages = [{'role': 'user', 'content': goal}]
    for _ in range(max_steps):
        resp = client.messages.create(
            model='claude-sonnet-4-6', max_tokens=1024,
            tools=tools, messages=messages,
        )
        messages.append({'role': 'assistant', 'content': resp.content})
        if resp.stop_reason == 'end_turn':
            final = next((b.text for b in resp.content if hasattr(b, 'text')), '')
            decision, comment = ask_fn(f'Agent finished. Output:\n{final}\n\nAccept?')
            if decision == HumanDecision.REJECT:
                messages = incorporate_human_feedback(
                    messages, decision, comment, 'final output'
                )
                continue  # re-run
            return final
        tool_results = []
        for block in resp.content:
            if block.type != 'tool_use':
                continue
            if is_risky(block.name, block.input):
                checkpoint = HumanCheckpoint(
                    name=f'{block.name}_gate',
                    prompt=f'Approve {block.name} with input {block.input}?',
                )
                decision, comment = human_review(
                    checkpoint, block.input, ask_fn
                )
                if decision != HumanDecision.APPROVE:
                    tool_results.append({
                        'type': 'tool_result',
                        'tool_use_id': block.id,
                        'content': f'Blocked by human: {comment}',
                        'is_error': True,
                    })
                    messages = incorporate_human_feedback(
                        messages, decision, comment, block.name
                    )
                    continue
            raw = tool_fns[block.name](**block.input)
            tool_results.append({
                'type': 'tool_result',
                'tool_use_id': block.id,
                'content': str(raw),
            })
        messages.append({'role': 'user', 'content': tool_results})
    return 'Max steps reached'

# Store human corrections so the agent can avoid the same mistake
# in future runs (or in later steps of the same run).

from dataclasses import dataclass, field

@dataclass
class FeedbackMemory:
    corrections: list[dict] = field(default_factory=list)

    def record(
        self,
        tool_name: str,
        original_input: dict,
        comment: str,
    ) -> None:
        self.corrections.append({
            'tool': tool_name,
            'input': original_input,
            'correction': comment,
        })

    def as_system_context(self) -> str:
        if not self.corrections:
            return ''
        lines = ['Previous human corrections in this session:']
        for c in self.corrections[-5:]:  # last 5 to stay concise
            lines.append(
                f'  - {c["tool"]} was blocked/modified: {c["correction"]}'
            )
        return '\n'.join(lines)

